class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def reverseList(head: ListNode) -> ListNode:
    prev = None
    current = head

    while current is not None:
        next_node = current.next # Sonraki düğümü kaydet
        current.next = prev      # Mevcut düğümün next'ini tersine çevir
        prev = current           # prev'i mevcut düğüme ilerlet
        current = next_node      # current'ı bir sonraki düğüme ilerlet

    return prev # prev, artık tersine çevrilmiş listenin başıdır
